SET
  @ID_fb0ac3f4 = 'C3F7F066-789A-42A2-ACFD-2C113B5D2E30'
SET
  @Name_fb0ac3f4 = N'Recent Entity Changes'
SET
  @CategoryID_fb0ac3f4 = 'AE8F2E3D-B5C3-4181-B00A-5C0107D377DB'
SET
  @Description_fb0ac3f4 = N'Returns recent record changes grouped by entity name. Accepts a lookbackDays parameter to control the time window.'
SET
  @SQL_fb0ac3f4 = N'-- Reusable base query: Returns recent record changes grouped by entity
-- Parameterized by lookbackDays (how far back to look)
SELECT
    e.Name AS EntityName,
    COUNT(*) AS ChangeCount,
    MAX(rc.CreatedAt) AS LatestChange,
    MIN(rc.CreatedAt) AS EarliestChange
FROM
    ${flyway:defaultSchema}.vwRecordChanges rc
    INNER JOIN ${flyway:defaultSchema}.vwEntities e ON e.ID = rc.EntityID
WHERE
    rc.CreatedAt >= DATEADD(DAY, -{{lookbackDays}}, GETUTCDATE())
GROUP BY
    e.Name
