SET
  @ID_12e10b63 = 'C2162354-AB2F-4244-8659-C5A4E213E9FA'
SET
  @Name_12e10b63 = N'User Activity Summary'
SET
  @CategoryID_12e10b63 = 'AE8F2E3D-B5C3-4181-B00A-5C0107D377DB'
SET
  @Description_12e10b63 = N'Composed query that joins Active Users with Recent Entity Changes to show each user''s recent activity level. Demonstrates the {{query:"..."}} composition syntax.'
SET
  @SQL_12e10b63 = N'-- Composed query: Joins Active Users with Recent Entity Changes
-- Demonstrates {{query:"..."}} composition syntax
-- References two reusable queries and combines their data
SELECT
    au.Name AS UserName,
    au.Email,
    au.Type AS UserType,
    COALESCE(rc.ChangeCount, 0) AS RecentChanges,
    rc.LatestChange
FROM
    {{query:"Demos/Active Users"}} au
    LEFT JOIN {{query:"Demos/Recent Entity Changes(lookbackDays=''30'')"}} rc
        ON rc.EntityName IN (
            SELECT e.Name
            FROM ${flyway:defaultSchema}.vwEntities e
            WHERE e.ID IN (
                SELECT DISTINCT EntityID
                FROM ${flyway:defaultSchema}.vwRecordChanges
                WHERE UserID = au.ID
            )
        )
ORDER BY
    COALESCE(rc.ChangeCount, 0) DESC,
    au.Name
'
SET
  @TechnicalDescription_12e10b63 = N'This query demonstrates MJ query composition by referencing two reusable queries:
1. {{query:"Demos/Active Users"}} - provides the user base
2. {{query:"Demos/Recent Entity Changes(lookbackDays=''30'')"}} - provides change metrics with a static 30-day lookback

At execution time, the composition engine resolves these references into CTEs before the SQL is sent to the database.'
